procedures.ap_GetAccountGameSlot:
/**
*Purpose            : 拌沥狼 霸烙 浇吩苞 鞘夸茄 沥焊甫 啊廉柯促.
*Record Set         : 弥辆 肺弊酒眶 矫埃, 浇吩 矫累老, 浇吩 目胶磐付捞令 厚飘(霸烙辑滚啊 汲沥茄)
*Error Code         : 绝澜
*History            : 2012-08-17 leehd@ncsoft.com SP created
					: 2012-08-20 leehd@ncsoft.com add onwer(dbo) at selecting table.
					                              return lastlogout to lastLogoutDate from lastLoginDate(typo error)
*/

CREATE       PROCEDURE [dbo].[ap_GetAccountGameSlot]
@gameAccountNo			INT,
@lastLogout		DATETIME OUTPUT,
@slotStartTime	DATETIME OUTPUT,
@slotCustomizeBitset	VARBINARY(8) OUTPUT
AS
SET NOCOUNT ON

SELECT 
@lastLogout = AE.lastLogoutDate,
@slotStartTime = AGS.gameSlotAvailStartDate,
@slotCustomizeBitset = AGS.gameSlotCustomizeBitSet 
FROM dbo.AccountETC AS AE WITH(NOLOCK)
LEFT OUTER JOIN dbo.AccountGameSlot AS AGS WITH(NOLOCK) ON AE.gameAccountNo = AGS.gameAccountNo
WHERE AE.gameAccountNo = @gameAccountNo

procedures.ap_GStat:
/**
*Purpose            : 拌沥狼惑怕沥焊甫啊廉柯促.
*Record Set         : 搬力咯何(荤侩救窃), 肺弊牢何啊沥焊, 版绊沥焊, 呕硼脚没咯何, 力犁沥焊,
					  殿废咯何, 付瘤阜肺弊牢辑滚, 力犁辆丰老(荤侩救窃), 陛瘤辑滚府胶飘
*Error Code         : 绝澜
*History            : 2008-10-20 Jaewon Ryu 弥檬累己
*/

CREATE       PROCEDURE [dbo].[ap_GStat]
@account		VARCHAR(14)
, @uid			INT OUTPUT 
, @payStat		INT OUTPUT 
, @loginFlag		INT OUTPUT
, @warnFlag		INT OUTPUT
, @blockFlag		INT OUTPUT
, @blockFlag2		INT OUTPUT 
, @subFlag		INT OUTPUT
, @lastworld		TINYINT OUTPUT
, @block_end_date		DATETIME OUTPUT
, @forbidden_servers	BINARY(16) OUTPUT	-- When forbidden server option is on
-- , @dormantFlag		INT OUTPUT			-- When dormant option is on
AS

SELECT	@uid = AA.gameAccountNo,
		@payStat = 0,
		@loginFlag = dbo.fn_ap_GetLoginFlag (AA.gameAccountNo, noticeFlag, authLimitTypeBitSet, gameAccountGradeCode, GETDATE()),
		@warnFlag = dbo.fn_ap_GetWarnFlag (AA.gameAccountNo, noticeFlag, GETDATE()),
		@blockFlag = dbo.fn_ap_GetBlockFlag (AA.gameAccountNo, accountStatusCode),
		@blockFlag2 = dbo.fn_ap_GetBlockFlag2 (AA.gameAccountNo, restrictFlag, GETDATE()),
		@subFlag = 0,
		@lastworld = AE.lastLoginGameServerNo,
		@block_end_date = NULL,		-- not in use
		@forbidden_servers = AE.banServerBitSet
FROM	AccountAuth AA INNER JOIN AccountETC AE ON (AA.gameAccountNo = AE.gameAccountNo)
WHERE	gameAccount = @account
